# ROBUSTNESS PHASE G — Malformed PDU resilience, CMAC key derivation,
#                      suppress-response bit, YAML ↔ simulator consistency
# Manually written, not generated by testgen.py. Do not delete.
#
# Covers:
#   TestMalformedPDUResilience   — simulator must never raise; always returns NRC or None
#   TestEndToEndCMACFlow         — AES-128-CMAC requestSeed → sendKey full round-trip
#   TestSuppressResponseBit      — 0x80 MSB on sub-fn byte: simulator must return None
#   TestYAMLSimulatorConsistency — _dids_meta / _routines_meta must match diagnostics_config.yaml
#
# Run: pytest test_robustness_G_resilience.py -v
from __future__ import annotations

import os
import sys

import pytest

sys.path.insert(0, os.path.dirname(__file__))
from conftest import (
    _inline_handle,
    _InlineEcuState,
    _EcuSimulator,
    SID_DIAGNOSTIC_SESSION_CONTROL,
    SID_ECU_RESET,
    SID_READ_DTC_INFO,
    SID_READ_DATA_BY_ID,
    SID_SECURITY_ACCESS,
    SID_WRITE_DATA_BY_ID,
    SID_ROUTINE_CONTROL,
    SID_TESTER_PRESENT,
    SID_NEGATIVE_RESPONSE,
    SESSION_DEFAULT,
    SESSION_EXTENDED,
    NRC_INCORRECT_MSG_LEN,
    NRC_REQUEST_OUT_OF_RANGE,
    NRC_SECURITY_ACCESS_DENIED,
    NRC_INVALID_KEY,
    NRC_SUB_FUNCTION_NOT_SUPPORTED,
    ALGO_SEED_LEN,
    ALGO_KEY_LEN,
    _LEVEL_KEYS,
)

EDS_ROOT  = os.path.abspath(os.path.join(os.path.dirname(__file__), "..", "..", "..", ".."))
YAML_PATH = os.path.join(EDS_ROOT, "examples", "basic_ecu", "diagnostics_config.yaml")

SID_COMMUNICATION_CONTROL = 0x28
SID_CONTROL_DTC_SETTING   = 0x85

NRC_SERVICE_NOT_SUPPORTED_IN_SESSION = 0x7F
NRC_EXCEEDED_NUMBER_OF_ATTEMPTS      = 0x36
NRC_SEQUENCE_ERROR                   = 0x24

_SESSION_MAP = {"default": 1, "extended": 3, "programming": 2}


def _sim():
    return _InlineEcuState()


def _req(state, pdu):
    return _inline_handle(pdu, state, False)


def _session(state, s):
    _inline_handle(bytes([SID_DIAGNOSTIC_SESSION_CONTROL, s]), state, False)


def _do_cmac_unlock(state, level=1):
    sub_seed = 2 * level - 1
    sub_key  = 2 * level
    resp = _req(state, bytes([SID_SECURITY_ACCESS, sub_seed]))
    if resp is None or resp[0] == SID_NEGATIVE_RESPONSE:
        return False, b''
    seed = bytes(resp[2:])
    key_material = _LEVEL_KEYS.get(level, _LEVEL_KEYS[1])
    key = _EcuSimulator._cmac(key_material, seed)[:ALGO_KEY_LEN]
    resp2 = _req(state, bytes([SID_SECURITY_ACCESS, sub_key]) + key)
    return (resp2 is not None and resp2[0] != SID_NEGATIVE_RESPONSE), key


# ===========================================================================
# TestMalformedPDUResilience
# ===========================================================================

class TestMalformedPDUResilience:
    """Inline simulator must return valid NRC bytes for any malformed input — never raise."""

    def test_empty_pdu_returns_nrc_13(self):
        resp = _req(_sim(), b'')
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_INCORRECT_MSG_LEN

    def test_unknown_sids_return_nrc_11(self):
        state = _sim()
        for sid in (0x00, 0x01, 0x20, 0x40, 0xAA, 0xFE, 0xFF):
            resp = _req(state, bytes([sid]))
            assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE, \
                f"SID 0x{sid:02X}: expected NRC response, got {resp}"
            assert resp[2] == 0x11, \
                f"SID 0x{sid:02X}: expected NRC 0x11 (serviceNotSupported), got 0x{resp[2]:02X}"

    def test_0x10_truncated_returns_nrc_13(self):
        resp = _req(_sim(), bytes([SID_DIAGNOSTIC_SESSION_CONTROL]))
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN

    def test_0x11_truncated_returns_nrc_13(self):
        resp = _req(_sim(), bytes([SID_ECU_RESET]))
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN

    def test_0x27_truncated_returns_nrc_13(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_SECURITY_ACCESS]))
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN

    def test_0x22_truncated_returns_nrc_13(self):
        resp = _req(_sim(), bytes([SID_READ_DATA_BY_ID]))
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN

    def test_0x2E_truncated_returns_nrc_13(self):
        resp = _req(_sim(), bytes([SID_WRITE_DATA_BY_ID, 0xF1]))
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN

    def test_0x31_truncated_returns_nrc_13(self):
        resp = _req(_sim(), bytes([SID_ROUTINE_CONTROL, 0x01, 0xFF]))
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN

    def test_0x28_truncated_returns_nrc_13(self):
        resp = _req(_sim(), bytes([SID_COMMUNICATION_CONTROL]))
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN

    def test_0x85_truncated_returns_nrc_13(self):
        resp = _req(_sim(), bytes([SID_CONTROL_DTC_SETTING]))
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN

    def test_0x19_truncated_returns_nrc_13(self):
        resp = _req(_sim(), bytes([SID_READ_DTC_INFO]))
        assert resp is not None and resp[2] == NRC_INCORRECT_MSG_LEN

    def test_0x10_invalid_sub_returns_nrc_12(self):
        for sub in (0x00, 0x04, 0x7F):
            resp = _req(_sim(), bytes([SID_DIAGNOSTIC_SESSION_CONTROL, sub]))
            assert resp is not None and resp[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED, \
                f"sub=0x{sub:02X}: expected NRC 0x12, got {resp.hex() if resp else None}"

    def test_all_256_sids_never_raise(self):
        """Every SID with no payload must return bytes or None — never raise."""
        state = _sim()
        for sid in range(256):
            try:
                resp = _req(state, bytes([sid]))
                assert resp is None or isinstance(resp, (bytes, bytearray)), \
                    f"SID 0x{sid:02X}: expected bytes or None, got {type(resp)}"
            except Exception as exc:
                pytest.fail(f"SID 0x{sid:02X} raised {type(exc).__name__}: {exc}")


# ===========================================================================
# TestEndToEndCMACFlow
# ===========================================================================

class TestEndToEndCMACFlow:
    """AES-128-CMAC requestSeed → sendKey full round-trip using the inline simulator."""

    def test_request_seed_level1_in_extended_session(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))
        assert resp is not None and resp[0] == 0x67, f"Expected 0x67 seed response, got {resp}"
        assert resp[1] == 0x01
        assert len(resp) == 2 + ALGO_SEED_LEN

    def test_seed_last_byte_encodes_level(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))
        seed = bytes(resp[2:])
        assert seed[-1] == 1, f"Expected seed last byte == level (1), got {seed[-1]}"

    def test_correct_cmac_key_grants_access_level1(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        ok, _ = _do_cmac_unlock(s, level=1)
        assert ok, "Level 1 unlock with correct CMAC key must succeed"

    def test_wrong_key_returns_nrc_invalid_key(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))  # requestSeed
        bad_key = bytes([0x00] * ALGO_KEY_LEN)
        resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x02]) + bad_key)
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_INVALID_KEY, f"Expected NRC 0x35, got 0x{resp[2]:02X}"

    def test_three_wrong_keys_triggers_lockout(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        for _ in range(3):
            _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))
            _req(s, bytes([SID_SECURITY_ACCESS, 0x02]) + bytes([0x00] * ALGO_KEY_LEN))
        resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))
        assert resp is not None and resp[2] == NRC_EXCEEDED_NUMBER_OF_ATTEMPTS, \
            f"Expected NRC 0x36, got {resp.hex() if resp else None}"

    def test_send_key_before_seed_returns_sequence_error(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x02]) + bytes([0x00] * ALGO_KEY_LEN))
        assert resp is not None and resp[2] == NRC_SEQUENCE_ERROR, \
            f"Expected NRC 0x24, got {resp.hex() if resp else None}"

    def test_already_unlocked_seed_is_all_zeros(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        ok, _ = _do_cmac_unlock(s, level=1)
        assert ok
        resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))
        seed = bytes(resp[2:])
        assert seed == bytes(ALGO_SEED_LEN), "Already-unlocked level must return all-zero seed"

    def test_level2_unlock_in_extended_session(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        ok, _ = _do_cmac_unlock(s, level=2)
        assert ok, "Level 2 unlock with correct CMAC key must succeed"

    def test_level1_and_level2_independent(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        ok1, _ = _do_cmac_unlock(s, level=1)
        ok2, _ = _do_cmac_unlock(s, level=2)
        assert ok1 and ok2, "Level 1 and Level 2 must be independently unlockable in one session"

    def test_seed_randomness_across_requests(self):
        seeds = set()
        for _ in range(5):
            s = _sim(); _session(s, SESSION_EXTENDED)
            resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))
            assert resp is not None and resp[0] == 0x67
            seeds.add(bytes(resp[2:]))
        assert len(seeds) >= 4, f"Expected random seeds; only {len(seeds)} unique values from 5 requests"

    def test_security_access_rejected_in_default_session(self):
        s = _sim()
        resp = _req(s, bytes([SID_SECURITY_ACCESS, 0x01]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SERVICE_NOT_SUPPORTED_IN_SESSION


# ===========================================================================
# TestSuppressResponseBit
# ===========================================================================

class TestSuppressResponseBit:
    """
    ISO 14229-1 §7.5.3: when bit 7 of the sub-function byte (0x80) is set,
    the ECU must NOT send any response (positive or negative). The inline
    simulator must return None for all such requests.

    Services 0x10 and 0x3E already handle this correctly.
    Services 0x11, 0x31, 0x28, 0x85 contain bugs — these tests expose them.
    """

    def test_0x10_suppress_bit_returns_none(self):
        """DiagnosticSessionControl 0x10 — already correct."""
        s = _sim()
        resp = _req(s, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, SESSION_DEFAULT | 0x80]))
        assert resp is None, f"0x10 with suppress bit: expected None, got {resp!r}"

    def test_0x3E_suppress_bit_returns_none(self):
        """TesterPresent 0x3E — already correct."""
        s = _sim()
        resp = _req(s, bytes([SID_TESTER_PRESENT, 0x80]))
        assert resp is None, f"0x3E with suppress bit: expected None, got {resp!r}"

    def test_0x11_suppress_bit_returns_none(self):
        """ECUReset 0x11 — suppress bit must silence the 0x51 positive response."""
        s = _sim()
        resp = _req(s, bytes([SID_ECU_RESET, 0x01 | 0x80]))
        assert resp is None, (
            f"0x11 suppress bit: expected None, got {resp!r} "
            "(BUG: missing 'if pdu[1] & 0x80: return None' before 'return bytes([0x51, sub])')"
        )

    def test_0x28_suppress_bit_returns_none(self):
        """CommunicationControl 0x28 — suppress bit must silence the 0x68 positive response."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_COMMUNICATION_CONTROL, 0x01 | 0x80]))
        assert resp is None, (
            f"0x28 suppress bit: expected None, got {resp!r} "
            "(BUG: bit stripped with & 0x7F but no 'if pdu[1] & 0x80: return None' before response)"
        )

    def test_0x85_suppress_bit_returns_none(self):
        """ControlDTCSetting 0x85 — suppress bit must silence the 0xC5 positive response."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_CONTROL_DTC_SETTING, 0x01 | 0x80]))
        assert resp is None, (
            f"0x85 suppress bit: expected None, got {resp!r} "
            "(BUG: bit stripped with & 0x7F but no 'if pdu[1] & 0x80: return None' before response)"
        )

    def test_0x31_suppress_bit_returns_none(self):
        """RoutineControl 0x31 — suppress bit must silence the 0x71 positive response."""
        s = _sim(); _session(s, SESSION_EXTENDED)
        # routine 0xFF00: extended session, security_level 0 — no unlock needed
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x01 | 0x80, 0xFF, 0x00]))
        assert resp is None, (
            f"0x31 suppress bit: expected None, got {resp!r} "
            "(BUG: sub_fn = pdu[1] should be pdu[1] & 0x7F; no None return for suppress bit)"
        )

    def test_0x11_without_suppress_bit_returns_positive(self):
        s = _sim()
        resp = _req(s, bytes([SID_ECU_RESET, 0x01]))
        assert resp is not None and resp[0] == 0x51, \
            f"0x11 without suppress bit: expected 0x51, got {resp!r}"

    def test_0x28_without_suppress_bit_returns_positive(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_COMMUNICATION_CONTROL, 0x01]))
        assert resp is not None and resp[0] == 0x68, \
            f"0x28 without suppress bit: expected 0x68, got {resp!r}"

    def test_0x85_without_suppress_bit_returns_positive(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_CONTROL_DTC_SETTING, 0x01]))
        assert resp is not None and resp[0] == 0xC5, \
            f"0x85 without suppress bit: expected 0xC5, got {resp!r}"

    def test_0x31_without_suppress_bit_returns_positive(self):
        s = _sim(); _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x01, 0xFF, 0x00]))
        assert resp is not None and resp[0] == 0x71, \
            f"0x31 without suppress bit: expected 0x71, got {resp!r}"

    def test_suppress_bit_on_multiple_valid_sessions(self):
        """Suppress bit must work regardless of session (extended and programming)."""
        for session_id in (SESSION_EXTENDED,):
            s = _sim(); _session(s, session_id)
            resp = _req(s, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, session_id | 0x80]))
            assert resp is None, \
                f"Session 0x{session_id:02X}: suppress bit on 0x10 must yield None"


# ===========================================================================
# TestYAMLSimulatorConsistency
# ===========================================================================

class TestYAMLSimulatorConsistency:
    """
    Verify _InlineEcuState._dids_meta and _routines_meta exactly mirror the
    source diagnostics_config.yaml for basic_ecu. Any drift here means the
    simulator is not testing the ECU it claims to simulate.
    """

    @pytest.fixture(scope="class")
    def yaml_cfg(self):
        try:
            import yaml
        except ImportError:
            pytest.skip("pyyaml not installed")
        if not os.path.isfile(YAML_PATH):
            pytest.skip(f"YAML not found: {YAML_PATH}")
        with open(YAML_PATH) as f:
            return yaml.safe_load(f)

    @pytest.fixture(scope="class")
    def sim_meta(self):
        s = _sim()
        return s._dids_meta, s._routines_meta

    def test_did_count_matches_yaml(self, yaml_cfg, sim_meta):
        dids_meta, _ = sim_meta
        yaml_count = len(yaml_cfg.get("dids", []))
        assert len(dids_meta) == yaml_count, \
            f"_dids_meta has {len(dids_meta)} DIDs but YAML has {yaml_count}"

    def test_all_yaml_did_ids_present_in_sim_meta(self, yaml_cfg, sim_meta):
        dids_meta, _ = sim_meta
        for did in yaml_cfg.get("dids", []):
            did_id = int(did["id"], 16)
            assert did_id in dids_meta, f"DID {did['id']} (0x{did_id:04X}) missing from _dids_meta"

    def test_did_data_lengths_match_yaml(self, yaml_cfg, sim_meta):
        dids_meta, _ = sim_meta
        for did in yaml_cfg.get("dids", []):
            did_id = int(did["id"], 16)
            if did_id not in dids_meta:
                continue
            assert dids_meta[did_id]["data_length"] == did["data_length"], \
                f"DID {did['id']}: data_length {dids_meta[did_id]['data_length']} != {did['data_length']}"

    def test_did_access_read_matches_yaml(self, yaml_cfg, sim_meta):
        dids_meta, _ = sim_meta
        for did in yaml_cfg.get("dids", []):
            did_id = int(did["id"], 16)
            if did_id not in dids_meta:
                continue
            expected = "read" in did.get("access", [])
            assert dids_meta[did_id]["access_read"] == expected, \
                f"DID {did['id']}: access_read mismatch"

    def test_did_access_write_matches_yaml(self, yaml_cfg, sim_meta):
        dids_meta, _ = sim_meta
        for did in yaml_cfg.get("dids", []):
            did_id = int(did["id"], 16)
            if did_id not in dids_meta:
                continue
            expected = "write" in did.get("access", [])
            assert dids_meta[did_id]["access_write"] == expected, \
                f"DID {did['id']}: access_write mismatch"

    def test_did_min_session_matches_yaml(self, yaml_cfg, sim_meta):
        dids_meta, _ = sim_meta
        for did in yaml_cfg.get("dids", []):
            did_id = int(did["id"], 16)
            if did_id not in dids_meta:
                continue
            expected_ord = _SESSION_MAP.get(did.get("min_session", "default"), 1)
            assert dids_meta[did_id]["min_session"] == expected_ord, \
                f"DID {did['id']}: min_session {dids_meta[did_id]['min_session']} != {expected_ord}"

    def test_did_read_sec_matches_yaml(self, yaml_cfg, sim_meta):
        dids_meta, _ = sim_meta
        for did in yaml_cfg.get("dids", []):
            did_id = int(did["id"], 16)
            if did_id not in dids_meta:
                continue
            assert dids_meta[did_id]["read_sec"] == did.get("read_security_level", 0), \
                f"DID {did['id']}: read_sec mismatch"

    def test_routine_count_matches_yaml(self, yaml_cfg, sim_meta):
        _, routines_meta = sim_meta
        yaml_count = len(yaml_cfg.get("routines", []))
        assert len(routines_meta) == yaml_count, \
            f"_routines_meta has {len(routines_meta)} routines but YAML has {yaml_count}"

    def test_all_yaml_routine_ids_present_in_sim_meta(self, yaml_cfg, sim_meta):
        _, routines_meta = sim_meta
        for r in yaml_cfg.get("routines", []):
            rid = int(r["id"], 16)
            assert rid in routines_meta, f"Routine {r['id']} (0x{rid:04X}) missing from _routines_meta"

    def test_routine_min_session_matches_yaml(self, yaml_cfg, sim_meta):
        _, routines_meta = sim_meta
        for r in yaml_cfg.get("routines", []):
            rid = int(r["id"], 16)
            if rid not in routines_meta:
                continue
            expected_ord = _SESSION_MAP.get(r.get("min_session", "default"), 1)
            assert routines_meta[rid]["min_session"] == expected_ord, \
                f"Routine {r['id']}: min_session {routines_meta[rid]['min_session']} != {expected_ord}"

    def test_routine_sec_level_matches_yaml(self, yaml_cfg, sim_meta):
        _, routines_meta = sim_meta
        for r in yaml_cfg.get("routines", []):
            rid = int(r["id"], 16)
            if rid not in routines_meta:
                continue
            assert routines_meta[rid]["sec_level"] == r.get("security_level", 0), \
                f"Routine {r['id']}: sec_level mismatch"

    def test_routine_support_matches_yaml(self, yaml_cfg, sim_meta):
        _, routines_meta = sim_meta
        for r in yaml_cfg.get("routines", []):
            rid = int(r["id"], 16)
            if rid not in routines_meta:
                continue
            expected = set(r.get("support", []))
            assert routines_meta[rid]["support"] == expected, \
                f"Routine {r['id']}: support {routines_meta[rid]['support']} != {expected}"
